// GovernanceManagerServiceServer is the server API for GovernanceManagerService service.
// All implementations must embed UnimplementedGovernanceManagerServiceServer
// for forward compatibility.
//
// GovernanceManagerService is the stable v1 inter-service contract for risk
// and release governance. It owns risk classification, review signals, gate
// decisions, release decisions and release safety-loop state.
type GovernanceManagerServiceServer interface {
	// CreateRiskProfile creates a risk profile for a project-owned or platform scope.
	CreateRiskProfile(context.Context, *CreateRiskProfileRequest) (*RiskProfileResponse, error)
	// CreateRiskProfileVersion creates an immutable set of risk rules and gate policies.
	CreateRiskProfileVersion(context.Context, *CreateRiskProfileVersionRequest) (*RiskProfileVersionResponse, error)
	// ActivateRiskProfileVersion activates one profile version for future assessments.
	ActivateRiskProfileVersion(context.Context, *ActivateRiskProfileVersionRequest) (*RiskProfileVersionResponse, error)
	// ArchiveRiskProfile archives a profile without deleting decision history.
	ArchiveRiskProfile(context.Context, *ArchiveRiskProfileRequest) (*RiskProfileResponse, error)
	// GetRiskProfile returns authoritative risk profile metadata.
	GetRiskProfile(context.Context, *GetRiskProfileRequest) (*RiskProfileResponse, error)
	// GetRiskProfileVersion returns one immutable profile version.
	GetRiskProfileVersion(context.Context, *GetRiskProfileVersionRequest) (*RiskProfileVersionResponse, error)
	// ListRiskProfiles returns profiles by scope and status.
	ListRiskProfiles(context.Context, *ListRiskProfilesRequest) (*ListRiskProfilesResponse, error)
	// ListRiskRules returns risk rules by profile version, kind and status.
	ListRiskRules(context.Context, *ListRiskRulesRequest) (*ListRiskRulesResponse, error)
	// ListGatePolicies returns gate policies by profile version, kind and status.
	ListGatePolicies(context.Context, *ListGatePoliciesRequest) (*ListGatePoliciesResponse, error)
	// EvaluateRisk creates an assessment for a transition, provider artifact, runtime job or release candidate.
	EvaluateRisk(context.Context, *EvaluateRiskRequest) (*RiskAssessmentResponse, error)
	// ReevaluateRisk recalculates an assessment after policy, evidence or signal changes.
	ReevaluateRisk(context.Context, *ReevaluateRiskRequest) (*RiskAssessmentResponse, error)
	// GetRiskAssessment returns one assessment with required gate summaries.
	GetRiskAssessment(context.Context, *GetRiskAssessmentRequest) (*RiskAssessmentResponse, error)
	// ListRiskAssessments returns assessments by target, project, risk class or status.
	ListRiskAssessments(context.Context, *ListRiskAssessmentsRequest) (*ListRiskAssessmentsResponse, error)
	// ListRiskFactors returns factors recorded for an assessment.
	ListRiskFactors(context.Context, *ListRiskFactorsRequest) (*ListRiskFactorsResponse, error)
	// RecordReviewSignal records a reviewer, QA, lexical, SRE, security or owner signal.
	RecordReviewSignal(context.Context, *RecordReviewSignalRequest) (*ReviewSignalResponse, error)
	// ListReviewSignals returns review signals by target, assessment, role or outcome.
	ListReviewSignals(context.Context, *ListReviewSignalsRequest) (*ListReviewSignalsResponse, error)
	// RequestGate creates a governance gate request and evidence package.
	RequestGate(context.Context, *RequestGateRequest) (*GateRequestResponse, error)
	// SubmitGateDecision records the final governance decision for a gate request.
	SubmitGateDecision(context.Context, *SubmitGateDecisionRequest) (*GateDecisionResponse, error)
	// CancelGate cancels an open governance gate request without owning delivery callbacks.
	CancelGate(context.Context, *CancelGateRequest) (*GateRequestResponse, error)
	// ExpireGate expires an open governance gate request after its delivery or policy timeout.
	ExpireGate(context.Context, *ExpireGateRequest) (*GateRequestResponse, error)
	// GetGateDecision returns one final governance gate decision.
	GetGateDecision(context.Context, *GetGateDecisionRequest) (*GateDecisionResponse, error)
	// ListGateDecisions returns final governance gate decisions by gate request or target, optionally refined by outcome.
	ListGateDecisions(context.Context, *ListGateDecisionsRequest) (*ListGateDecisionsResponse, error)
	// GetGateRequest returns one gate request and its final decision when present.
	GetGateRequest(context.Context, *GetGateRequestRequest) (*GateRequestResponse, error)
	// ListGateRequests returns gate requests by target or assessment, optionally refined by status.
	ListGateRequests(context.Context, *ListGateRequestsRequest) (*ListGateRequestsResponse, error)
	// BuildReleaseDecisionPackage builds a bounded evidence package for a release candidate.
	BuildReleaseDecisionPackage(context.Context, *BuildReleaseDecisionPackageRequest) (*ReleaseDecisionPackageResponse, error)
	// GetReleaseDecisionPackage returns one release decision package.
	GetReleaseDecisionPackage(context.Context, *GetReleaseDecisionPackageRequest) (*ReleaseDecisionPackageResponse, error)
	// ListReleaseDecisionPackages returns release packages by project, candidate or status.
	ListReleaseDecisionPackages(context.Context, *ListReleaseDecisionPackagesRequest) (*ListReleaseDecisionPackagesResponse, error)
	// RequestReleaseDecision starts release decision evaluation or required gate flow.
	RequestReleaseDecision(context.Context, *RequestReleaseDecisionRequest) (*ReleaseDecisionResponse, error)
	// SubmitReleaseDecision records a go/no-go/hold/rollback/follow-up release decision.
	SubmitReleaseDecision(context.Context, *SubmitReleaseDecisionRequest) (*ReleaseDecisionResponse, error)
	// GetReleaseDecision returns one release decision.
	GetReleaseDecision(context.Context, *GetReleaseDecisionRequest) (*ReleaseDecisionResponse, error)
	// ListReleaseDecisions returns release decisions by package, project, status or outcome.
	ListReleaseDecisions(context.Context, *ListReleaseDecisionsRequest) (*ListReleaseDecisionsResponse, error)
	// RecordBlockingSignal records a signal that blocks a transition or release.
	RecordBlockingSignal(context.Context, *RecordBlockingSignalRequest) (*BlockingSignalResponse, error)
	// ResolveBlockingSignal resolves or dismisses an active blocking signal.
	ResolveBlockingSignal(context.Context, *ResolveBlockingSignalRequest) (*BlockingSignalResponse, error)
	// ListBlockingSignals returns active or historical blocking signals.
	ListBlockingSignals(context.Context, *ListBlockingSignalsRequest) (*ListBlockingSignalsResponse, error)
	// RecordReleaseSafetyState records a release safety-loop state transition.
	RecordReleaseSafetyState(context.Context, *RecordReleaseSafetyStateRequest) (*ReleaseSafetyStateResponse, error)
	// GetReleaseSafetyState returns current safety-loop state for a release package.
	GetReleaseSafetyState(context.Context, *GetReleaseSafetyStateRequest) (*ReleaseSafetyStateResponse, error)
	mustEmbedUnimplementedGovernanceManagerServiceServer()
}

